module top_module(input wire rx_in, clk, rst, brg_en, 
		output wire shift_0, shift_15);reg [15:0] reset_reg, next_shift_reg;

	assign shift_15 = reset_reg[15];
	assign shift_0 = reset_reg[0];

	always @(posedge clk, posedge rst) begin
		if (rst) begin
			reset_reg <= 16'hFFFF;
		end else begin
			reset_reg <= next_shift_reg;
		end
	end

	always @(*) begin
		if (brg_en) begin
			next_shift_reg <= {rx_in, reset_reg[15:1]};
		end else begin
			next_shift_reg <= reset_reg;
		end
	end

endmodule
